17	type Scenario = {
18	  customer: Customer;
19	  steps: Step[];
20	};
21	
22	type QuoteResult = { premium: number };
23	
24	type ClaimResult = { payout: number; remainingCap: number };
25	
26	type StepResult = QuoteResult | ClaimResult;
27	
28	type ScenarioResult = {
29	  results: StepResult[];
30	};
